import{_ as r,o as a,c as d,ae as o}from"./chunks/framework.BeVX27ge.js";const c=JSON.parse('{"title":"Prompt 管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/admin-prompts.md","filePath":"zh-TW/admin-prompts.md"}'),e={name:"zh-TW/admin-prompts.md"};function l(h,t,i,p,n,m){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="prompt-管理" tabindex="-1">Prompt 管理 <a class="header-anchor" href="#prompt-管理" aria-label="Permalink to &quot;Prompt 管理&quot;">​</a></h1><blockquote><p>控制 AI 客戶的行為模式，打造最貼近真實的練習體驗</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>Prompt（提示詞）是控制 AI 行為的核心指令。透過 Prompt 管理功能，管理員可以調整 AI 客戶的回應方式、評量標準、角色生成規則等，確保練習體驗符合公司的培訓目標。</p><blockquote><p>此功能僅對具有 Prompt 管理權限的管理員開放。</p></blockquote><h2 id="進入方式" tabindex="-1">進入方式 <a class="header-anchor" href="#進入方式" aria-label="Permalink to &quot;進入方式&quot;">​</a></h2><ol><li>點擊頁面右上方的 <strong>管理設定圖示</strong>（齒輪）</li><li>在管理員後台中選擇「Prompt 管理」</li></ol><hr><h2 id="頁面結構" tabindex="-1">頁面結構 <a class="header-anchor" href="#頁面結構" aria-label="Permalink to &quot;頁面結構&quot;">​</a></h2><p>頁面分為三個主要區域：</p><table tabindex="0"><thead><tr><th>區域</th><th>說明</th></tr></thead><tbody><tr><td>標題列</td><td>公司/部門選擇、版本選擇、操作按鈕</td></tr><tr><td>Prompt 卡片列表</td><td>顯示目前版本下所有 Prompt 卡片</td></tr><tr><td>編輯面板</td><td>右側滑出面板，顯示選中 Prompt 的詳細編輯介面</td></tr></tbody></table><hr><h2 id="基本操作流程" tabindex="-1">基本操作流程 <a class="header-anchor" href="#基本操作流程" aria-label="Permalink to &quot;基本操作流程&quot;">​</a></h2><h3 id="步驟-1-選擇公司與部門" tabindex="-1">步驟 1：選擇公司與部門 <a class="header-anchor" href="#步驟-1-選擇公司與部門" aria-label="Permalink to &quot;步驟 1：選擇公司與部門&quot;">​</a></h3><p>在標題列中選擇要管理的公司與部門：</p><ul><li><strong>公司</strong> — 下拉選單選擇公司（提示：「請選擇公司」）</li><li><strong>部門</strong> — 下拉選單選擇部門（提示：「請先選擇公司以查看部門」）</li></ul><h3 id="步驟-2-選擇-prompt-版本" tabindex="-1">步驟 2：選擇 Prompt 版本 <a class="header-anchor" href="#步驟-2-選擇-prompt-版本" aria-label="Permalink to &quot;步驟 2：選擇 Prompt 版本&quot;">​</a></h3><p>每套 Prompt 可以有多個版本，選擇要查看或編輯的版本：</p><ul><li>下拉選單顯示所有可用版本（提示：「請選擇提示詞版本」）</li><li>標示「當前版本」的即為目前啟用中的版本</li></ul><h3 id="步驟-3-查看與編輯" tabindex="-1">步驟 3：查看與編輯 <a class="header-anchor" href="#步驟-3-查看與編輯" aria-label="Permalink to &quot;步驟 3：查看與編輯&quot;">​</a></h3><p>選擇版本後，頁面會顯示該版本下的所有 Prompt 卡片。</p><hr><h2 id="prompt-卡片" tabindex="-1">Prompt 卡片 <a class="header-anchor" href="#prompt-卡片" aria-label="Permalink to &quot;Prompt 卡片&quot;">​</a></h2><p>每張 Prompt 卡片顯示以下資訊：</p><table tabindex="0"><thead><tr><th>元素</th><th>說明</th></tr></thead><tbody><tr><td>名稱</td><td>Prompt 的唯一識別名稱</td></tr><tr><td>描述</td><td>Prompt 的簡要說明</td></tr><tr><td>類別標籤</td><td>顯示 Prompt 所屬的類別（見下方類別說明）</td></tr><tr><td>使用中標籤</td><td>如果此 Prompt 已發布啟用，會顯示「使用中」標籤</td></tr><tr><td>編輯按鈕</td><td>開啟右側編輯面板</td></tr><tr><td>刪除按鈕</td><td>刪除此 Prompt（會彈出確認訊息）</td></tr></tbody></table><h3 id="prompt-類別" tabindex="-1">Prompt 類別 <a class="header-anchor" href="#prompt-類別" aria-label="Permalink to &quot;Prompt 類別&quot;">​</a></h3><table tabindex="0"><thead><tr><th>類別</th><th>說明</th></tr></thead><tbody><tr><td>Character</td><td>客戶角色生成相關的指令</td></tr><tr><td>Judge</td><td>評量與判斷相關的指令</td></tr><tr><td>System</td><td>系統層級的基礎指令</td></tr><tr><td>GenerationAI</td><td>AI 生成行為的指令</td></tr><tr><td>CustomerAI</td><td>客戶 AI 的回應行為指令</td></tr><tr><td>MentorAI</td><td>導師 AI 的評核行為指令</td></tr><tr><td>Other</td><td>其他類別</td></tr></tbody></table><hr><h2 id="編輯-prompt" tabindex="-1">編輯 Prompt <a class="header-anchor" href="#編輯-prompt" aria-label="Permalink to &quot;編輯 Prompt&quot;">​</a></h2><p>點擊 Prompt 卡片上的「編輯」按鈕，右側會滑出編輯面板。</p><h3 id="編輯欄位" tabindex="-1">編輯欄位 <a class="header-anchor" href="#編輯欄位" aria-label="Permalink to &quot;編輯欄位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>欄位</th><th>說明</th></tr></thead><tbody><tr><td>名稱</td><td>Prompt 的唯一識別名稱。提示：「名稱必須唯一，用於程式中引用提示詞」</td></tr><tr><td>類別</td><td>下拉選單，選擇 Prompt 類別</td></tr><tr><td>描述</td><td>Prompt 的功能說明文字</td></tr><tr><td>提示詞內容</td><td>大型文字編輯區，輸入完整的 Prompt 指令文字</td></tr><tr><td>提示詞用途描述</td><td>說明此 Prompt 的用途與預期效果</td></tr></tbody></table><h3 id="變數系統" tabindex="-1">變數系統 <a class="header-anchor" href="#變數系統" aria-label="Permalink to &quot;變數系統&quot;">​</a></h3><p>在提示詞內容中可以使用大括號包含變數，系統會在執行時自動替換為實際值。</p><p>提示：「您可以使用大括號包含變數，例如 <code>{question}</code>, <code>{character_detail}</code> 等」</p><p>常見變數：</p><table tabindex="0"><thead><tr><th>變數</th><th>說明</th></tr></thead><tbody><tr><td><code>{question}</code></td><td>使用者的對話訊息</td></tr><tr><td><code>{character_detail}</code></td><td>客戶角色的詳細設定資料</td></tr><tr><td><code>{character_data}</code></td><td>客戶角色的基本資料</td></tr><tr><td><code>{conversation_history}</code></td><td>對話歷史紀錄</td></tr><tr><td><code>{stage_description}</code></td><td>當前銷售階段的描述</td></tr></tbody></table><blockquote><p>可用的變數會依 Prompt 類別有所不同，請參考各 Prompt 類別的說明。</p></blockquote><h3 id="未儲存變更提示" tabindex="-1">未儲存變更提示 <a class="header-anchor" href="#未儲存變更提示" aria-label="Permalink to &quot;未儲存變更提示&quot;">​</a></h3><p>當您修改了 Prompt 內容但尚未儲存時，系統會顯示提示：「您有尚未儲存的變更」。</p><hr><h2 id="版本管理" tabindex="-1">版本管理 <a class="header-anchor" href="#版本管理" aria-label="Permalink to &quot;版本管理&quot;">​</a></h2><p>Prompt 版本管理讓您在不影響目前運作的情況下，修改與測試新的 Prompt 設定。</p><h3 id="操作說明" tabindex="-1">操作說明 <a class="header-anchor" href="#操作說明" aria-label="Permalink to &quot;操作說明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>說明</th></tr></thead><tbody><tr><td>新增提示詞</td><td>在目前版本中新增一個 Prompt</td></tr><tr><td>新增版本</td><td>以目前版本為基礎，建立新版本（複製所有 Prompt）</td></tr><tr><td>新增版本並發布</td><td>建立新版本並同時設為啟用版本</td></tr><tr><td>儲存並發布</td><td>儲存目前的修改並將此版本設為啟用</td></tr><tr><td>另存</td><td>將目前修改儲存為新版本</td></tr><tr><td>另存並發布</td><td>將目前修改儲存為新版本並設為啟用</td></tr><tr><td>發布</td><td>將選中的版本設為啟用版本</td></tr></tbody></table><h3 id="版本生效規則" tabindex="-1">版本生效規則 <a class="header-anchor" href="#版本生效規則" aria-label="Permalink to &quot;版本生效規則&quot;">​</a></h3><ul><li>只有被「發布」（啟用）的版本才會在實際對話中生效</li><li>同一時間只有一個版本處於啟用狀態</li><li>修改非啟用版本不會影響目前的使用者體驗</li><li>切換啟用版本會立即生效，新的對話會使用新版本</li><li>已進行中的對話不受版本切換影響</li></ul><hr><h2 id="新增-prompt" tabindex="-1">新增 Prompt <a class="header-anchor" href="#新增-prompt" aria-label="Permalink to &quot;新增 Prompt&quot;">​</a></h2><ol><li>點擊標題列的 <strong>「新增提示詞」</strong> 按鈕</li><li>右側開啟空白的編輯面板</li><li>填寫所有必要欄位（名稱、類別、內容等）</li><li>點擊儲存</li></ol><hr><h2 id="刪除-prompt" tabindex="-1">刪除 Prompt <a class="header-anchor" href="#刪除-prompt" aria-label="Permalink to &quot;刪除 Prompt&quot;">​</a></h2><ol><li>在 Prompt 卡片上點擊 <strong>「刪除」</strong> 按鈕</li><li>系統彈出確認對話框：「確定要刪除提示詞 &quot;XXX&quot; 嗎？」</li><li>確認後刪除</li></ol><blockquote><p>刪除正在使用中的 Prompt 可能影響系統運作，請謹慎操作。</p></blockquote><hr><h2 id="最佳實踐" tabindex="-1">最佳實踐 <a class="header-anchor" href="#最佳實踐" aria-label="Permalink to &quot;最佳實踐&quot;">​</a></h2><h3 id="prompt-修改建議" tabindex="-1">Prompt 修改建議 <a class="header-anchor" href="#prompt-修改建議" aria-label="Permalink to &quot;Prompt 修改建議&quot;">​</a></h3><ol><li><strong>先建立新版本</strong> — 不要直接修改啟用中的版本</li><li><strong>小幅調整</strong> — 一次只修改少量內容，便於追蹤效果</li><li><strong>充分測試</strong> — 修改後先在新版本中測試，確認效果再發布</li><li><strong>保留歷史</strong> — 保留舊版本以便在需要時快速回退</li></ol><h3 id="常見調整情境" tabindex="-1">常見調整情境 <a class="header-anchor" href="#常見調整情境" aria-label="Permalink to &quot;常見調整情境&quot;">​</a></h3><table tabindex="0"><thead><tr><th>需求</th><th>建議調整的 Prompt 類別</th></tr></thead><tbody><tr><td>客戶反應不夠真實</td><td>CustomerAI</td></tr><tr><td>評量標準需要調整</td><td>Judge、MentorAI</td></tr><tr><td>角色生成結果不理想</td><td>Character</td></tr><tr><td>對話風格需要改變</td><td>CustomerAI、GenerationAI</td></tr></tbody></table><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>管理 <a href="./admin-stages.html">銷售階段</a> 設定練習標準</li><li>維護 <a href="./admin-knowledge.html">知識庫</a> 充實學習資源</li><li>管理 <a href="./admin-users.html">使用者帳號</a></li></ul>',63)])])}const b=r(e,[["render",l]]);export{c as __pageData,b as default};
